  generateGitHubActionsConfig() {
    return `# .github/workflows/ci.yml
# Best practices for package-lock.json in GitHub Actions
name: CI

on:
  push:
    branches: [main, develop]
  pull_request:
    branches: [main]

jobs:
  build:
    runs-on: ubuntu-latest
    
    strategy:
      matrix:
        node-version: [18.x, 20.x]

    steps:
      - uses: actions/checkout@v4
      
      - name: Use Node.js \${{ matrix.node-version }}
        uses: actions/setup-node@v4
        with:
          node-version: \${{ matrix.node-version }}
          # Enable built-in npm cache based on package-lock.json
          cache: 'npm'
      
      # IMPORTANT: Use 'npm ci' instead of 'npm install' in CI
      # npm ci:
      #   - Deletes node_modules and installs from scratch
      #   - Uses EXACT versions from package-lock.json
      #   - Fails if lock file is out of sync
      #   - Is faster for clean installs
      - name: Install dependencies
        run: npm ci
      
      # Verify no lock file changes occurred (drift detection)
      - name: Verify lock file integrity
        run: |
          if [ -n "$(git status --porcelain package-lock.json)" ]; then
            echo "❌ package-lock.json was modified during install!"
            echo "This means the lock file was out of sync."
            echo "Run 'npm install' locally and commit the changes."
            git diff package-lock.json
            exit 1
          fi
      
      - name: Run tests
        run: npm test
      
      - name: Security audit
        run: npm audit --audit-level=high

  # Separate job for dependency updates (run on schedule)
  dependency-check:
    runs-on: ubuntu-latest
    if: github.event_name == 'schedule'
    steps:
      - uses: actions/checkout@v4
      - uses: actions/setup-node@v4
        with:
          node-version: 20.x
          cache: 'npm'
      - run: npm ci
      - name: Check for outdated packages
        run: npm outdated || true
      - name: Security audit
        run: npm audit --json > audit-report.json || true
      - uses: actions/upload-artifact@v4
        with:
          name: audit-report
          path: audit-report.json`;
  }

  generateGitLabCIConfig() {
    return `# .gitlab-ci.yml
# Best practices for package-lock.json in GitLab CI

image: node:20-alpine

# Cache node_modules based on package-lock.json hash
cache:
  key:
    files:
      - package-lock.json
  paths:
    - node_modules/
  policy: pull-push

stages:
  - install
  - validate
  - test
  - build

install:
  stage: install
  script:
    # Always use npm ci in CI environments
    - npm ci --cache .npm --prefer-offline
  cache:
    key:
      files:
        - package-lock.json
    paths:
      - node_modules/
      - .npm/
    policy: push

validate-lockfile:
  stage: validate
  script:
    - npm ci
    # Ensure lock file wasn't modified
    - >
      if [ -n "$(git status --porcelain package-lock.json)" ]; then
        echo "Lock file drift detected!";
        exit 1;
      fi
    # Run security audit
    - npm audit --audit-level=moderate

test:
  stage: test
  script:
    - npm ci
    - npm test

build:
  stage: build
  script:
    # Production install - skip devDependencies
    - npm ci --omit=dev
    - npm run build
  artifacts:
    paths:
      - dist/`;
  }

